CREATE TABLE IF NOT EXISTS "TB_HISTORICO_LANCAMENTO"
(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CORRELATION_ID" UUID NOT NULL,
    "TIPO" CHAR(1) NOT NULL,
    "DATA_LANCAMENTO" TIMESTAMPTZ NOT NULL,
    "VALOR" NUMERIC(18, 2) NOT NULL,
    "DESCRICAO" VARCHAR(100) NULL,
    "DATA_PROCESSAMENTO" TIMESTAMPTZ NOT NULL,
    CONSTRAINT "UK_TB_HISTORICO_LANCAMENTO_CORRELATION_ID" UNIQUE ("CORRELATION_ID"),
    CONSTRAINT "CK_TB_HISTORICO_LANCAMENTO_TIPO" CHECK ("TIPO" IN ('D', 'C')),
    CONSTRAINT "CK_TB_HISTORICO_LANCAMENTO_VALOR" CHECK ("VALOR" > 0)
);

CREATE INDEX IF NOT EXISTS "IX_TB_HISTORICO_LANCAMENTO_DATA_LANCAMENTO"
    ON "TB_HISTORICO_LANCAMENTO" ("DATA_LANCAMENTO");

CREATE TABLE IF NOT EXISTS "TB_SALDO_CONSOLIDADO_DIARIO"
(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "DATA_REFERENCIA" DATE NOT NULL,
    "TOTAL_CREDITOS" NUMERIC(18, 2) NOT NULL DEFAULT 0,
    "TOTAL_DEBITOS" NUMERIC(18, 2) NOT NULL DEFAULT 0,
    "SALDO_DIARIO_CONSOLIDADO" NUMERIC(18, 2) NOT NULL DEFAULT 0,
    "DATA_ATUALIZACAO" TIMESTAMPTZ NOT NULL,
    CONSTRAINT "UK_TB_SALDO_CONSOLIDADO_DIARIO_DATA_REFERENCIA" UNIQUE ("DATA_REFERENCIA"),
    CONSTRAINT "CK_TB_SALDO_CONSOLIDADO_DIARIO_TOTAL_CREDITOS" CHECK ("TOTAL_CREDITOS" >= 0),
    CONSTRAINT "CK_TB_SALDO_CONSOLIDADO_DIARIO_TOTAL_DEBITOS" CHECK ("TOTAL_DEBITOS" >= 0)
);
